INSERT INTO poems (
  poet_id, poem_no, volume, title_zh, title_ko, category, meter, body_zh,
  is_notable, status, quality, review_memo
)
SELECT
  p.id,
  COALESCE(existing_poem_count.max_poem_no, 0)
    + row_number() OVER (PARTITION BY p.id ORDER BY ip.title_zh, ip.body_zh)::integer,
  ip.volume::integer, ip.title_zh, ip.title_ko, ip.category, ip.meter::integer, ip.body_zh,
  TRUE, ip.status, ip.quality, ip.review_memo
FROM input_poems ip
JOIN poets p ON p.title_id = ip.poet_slug
LEFT JOIN LATERAL (
  SELECT max(poem_no) AS max_poem_no
  FROM poems
  WHERE poet_id = p.id
) existing_poem_count ON TRUE
WHERE NOT EXISTS (
  SELECT 1
  FROM poems existing
  WHERE existing.poet_id = p.id
    AND existing.title_zh = ip.title_zh
    AND existing.body_zh = ip.body_zh
);

UPDATE poets p
SET poem_count = sub.cnt
FROM (
  SELECT poet_id, count(*)::integer AS cnt
  FROM poems
  WHERE poet_id IN (SELECT id FROM poets WHERE title_id IN ('cnpreqin-d9cfb1495fcebc18', 'cnpreqin-f48dff99e660bf88', 'cnpreqin-987737189eb9dcd1', 'cnpreqin-53bbb09e02a6c4bb', 'cnpreqin-ad3e122891447e2c', 'cnjin-55ea8c5fa743322e', 'candidate-song-6b50-967d-4fee', 'candidate-song-6797-900b', 'candidate-song-9678-904a', 'candidate-song-8303-6210-5927', 'candidate-song-66fe-978f', 'candidate-song-8d99-4f76', 'candidate-song-6b50-967d-7d93', 'candidate-song-5f6d-6c5d-792a', 'candidate-song-8607-980c', 'candidate-song-8607-6d35', 'candidate-song-90b5-96cd', 'candidate-song-674e-5fa9', 'candidate-song-738b-79b9-5041', 'candidate-song-674e-6e05-7167', 'candidate-song-8607-821c-6b3d', 'candidate-song-6731-71b9', 'candidate-song-675c-8012', 'candidate-song-8607-8efe', 'candidate-song-6797-6d2a', 'candidate-song-664f-6b8a', 'candidate-song-8521-8944', 'candidate-song-738b-73ea', 'candidate-song-9ec3-5ead-5805', 'candidate-song-91cb-60e0-6d2a', 'candidate-song-5f35-8012', 'candidate-song-7a0b-9865', 'candidate-song-50e7-5fd7-5b89', 'candidate-song-5f90-5143-5091', 'candidate-song-6731-6dd1-771f', 'candidate-song-738b-4ee4'))
